"use client";

import { useState, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Menu, Sparkles, Diamond, Plus, Mic, ChevronDown, Zap } from "lucide-react";
import Sidebar from "../components/Sidebar";
import MotionMessage from "../components/MotionMessage";

interface Message {
  id: string;
  role: "user" | "assistant";
  content: string;
}

interface Chat {
  id: string;
  title: string;
  messages: Message[];
  timestamp: Date;
}

export default function GeminiChatPage() {
  const [chats, setChats] = useState<Chat[]>([]);
  const [currentChatId, setCurrentChatId] = useState<string | null>(null);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [activeEngine, setActiveEngine] = useState<"groq" | "hf">("groq");
  const [isLoading, setIsLoading] = useState(false);
  const [inputValue, setInputValue] = useState("");
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [chats, currentChatId]);

  const currentChat = chats.find((c) => c.id === currentChatId);

  const handleNewChat = () => {
    const newChat: Chat = {
      id: Date.now().toString(),
      title: "New conversation",
      messages: [],
      timestamp: new Date(),
    };
    setChats((prev) => [newChat, ...prev]);
    setCurrentChatId(newChat.id);
    setSidebarOpen(false);
  };

  const handleSelectChat = (id: string) => {
    setCurrentChatId(id);
    setSidebarOpen(false);
  };

  const handleSendMessage = async (content: string) => {
    if (!content.trim()) return;

    let chatId = currentChatId;
    if (!chatId) {
      const newChat: Chat = {
        id: Date.now().toString(),
        title: content.slice(0, 30) + (content.length > 30 ? "..." : ""),
        messages: [],
        timestamp: new Date(),
      };
      setChats((prev) => [newChat, ...prev]);
      chatId = newChat.id;
      setCurrentChatId(chatId);
    }

    const userMessage: Message = {
      id: Date.now().toString(),
      role: "user",
      content,
    };

    setChats((prev) =>
      prev.map((chat) =>
        chat.id === chatId
          ? { ...chat, messages: [...chat.messages, userMessage] }
          : chat
      )
    );

    setInputValue("");
    setIsLoading(true);
    setTimeout(() => {
      const aiMessage: Message = {
        id: (Date.now() + 1).toString(),
        role: "assistant",
        content: `I'm Nyati-core01. You said: "${content}"\n\nThis is a simulated response.`,
      };

      setChats((prev) =>
        prev.map((chat) =>
          chat.id === chatId
            ? { ...chat, messages: [...chat.messages, aiMessage] }
            : chat
        )
      );
      setIsLoading(false);
    }, 1500);
  };

  const handleSwitchEngine = () => {
    setActiveEngine((prev) => (prev === "groq" ? "hf" : "groq"));
  };

  const quickActions = [
    { icon: "✨", label: "Create image" },
    { icon: "🎵", label: "Create music" },
    { icon: "📝", label: "Write anything" },
    { icon: "📚", label: "Help me learn" },
    { icon: "🚀", label: "Boost my day" },
  ];

  return (
    <div className="flex h-screen bg-[#0d0d0d] text-white overflow-hidden">
      {/* Minimal Sidebar */}
      <Sidebar
        isOpen={sidebarOpen}
        setIsOpen={setSidebarOpen}
        onNewChat={handleNewChat}
        chats={chats}
        currentChatId={currentChatId}
        onSelectChat={handleSelectChat}
        activeEngine={activeEngine}
        onSwitchEngine={handleSwitchEngine}
      />

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 relative">
        {/* Top Header */}
        <header className="flex items-center px-4 py-3 z-10">
          <button
            onClick={() => setSidebarOpen(true)}
            className="p-2 hover:bg-white/10 rounded-full transition-colors"
          >
            <Menu size={20} className="text-gray-400" />
          </button>
          
          <span className="flex-1 text-center font-medium text-gray-300 md:text-left md:flex-none md:ml-3">
            Koda-A
          </span>
        </header>

        {/* Chat Messages */}
        <div className="flex-1 overflow-y-auto px-4">
          <div className="max-w-3xl mx-auto">
            {currentChat && currentChat.messages.length > 0 ? (
              <div className="space-y-6 py-8 pb-40">
                <AnimatePresence mode="popLayout">
                  {currentChat.messages.map((message) => (
                    <MotionMessage
                      key={message.id}
                      role={message.role}
                      content={message.content}
                    />
                  ))}
                </AnimatePresence>
                {isLoading && (
                  <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    className="flex gap-4 py-4"
                  >
                    <div className="w-8 h-8 rounded-full bg-[#1e1e1e] flex items-center justify-center">
                      <Sparkles size={16} className="text-blue-400" />
                    </div>
                    <div className="flex-1 pt-1 space-y-2">
                      <div className="h-4 bg-gradient-to-r from-[#2a2a2a] via-[#3a3a3a] to-[#2a2a2a] rounded animate-pulse w-3/4" />
                      <div className="h-4 bg-gradient-to-r from-[#2a2a2a] via-[#3a3a3a] to-[#2a2a2a] rounded animate-pulse w-1/2" />
                    </div>
                  </motion.div>
                )}
                <div ref={messagesEndRef} />
              </div>
            ) : (
              /* Welcome Screen - Mobile: left-aligned, Desktop: centered */
              <div className="flex flex-col justify-center min-h-[50vh] md:items-center md:justify-center md:min-h-[60vh] px-2 md:px-0">
                <motion.div
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="md:text-center"
                >
                  {/* Greeting */}
                  <div className="flex items-center gap-2 mb-2 md:justify-center">
                    <Diamond size={20} className="text-blue-400 fill-blue-400" />
                    <span className="text-xl text-gray-300">Hi raymond</span>
                  </div>
                  
                  {/* Main question */}
                  <h1 className="text-3xl md:text-5xl font-normal text-white mb-8 md:mb-12">
                    Where should we start?
                  </h1>
                  
                  {/* Mobile: Vertical list of quick actions */}
                  <div className="flex flex-col gap-3 md:hidden">
                    {[
                      { icon: "✨", label: "Create image" },
                      { icon: "📝", label: "Write anything" },
                      { icon: "💡", label: "Build an idea" },
                      { icon: "🔬", label: "Deep Research" },
                    ].map((action, index) => (
                      <motion.button
                        key={index}
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        transition={{ delay: index * 0.1 }}
                        onClick={() => handleSendMessage(action.label)}
                        className="flex items-center gap-3 py-3 text-gray-300 hover:text-white transition-colors text-left"
                      >
                        <span>{action.icon}</span>
                        <span>{action.label}</span>
                      </motion.button>
                    ))}
                  </div>
                </motion.div>
              </div>
            )}
          </div>
        </div>

        {/* Input Section - Gemini Style */}
        <div className="px-4 pb-6">
          <div className="max-w-3xl mx-auto">
            {/* Input Pill */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="bg-[#1e1e1e] rounded-3xl p-4 border border-[#2a2a2a] hover:border-[#3a3a3a] transition-colors"
            >
              <div className="flex items-center gap-3">
                <input
                  type="text"
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === "Enter") {
                      handleSendMessage(inputValue);
                    }
                  }}
                  placeholder="Ask Koda 3"
                  className="flex-1 bg-transparent border-none outline-none text-white text-lg placeholder:text-gray-500"
                />
              </div>
              
              {/* Bottom row with buttons */}
              <div className="flex items-center justify-between mt-4">
                <div className="flex items-center gap-2">
                  <button className="p-2 hover:bg-white/10 rounded-full transition-colors">
                    <Plus size={20} className="text-gray-400" />
                  </button>
                  <button className="flex items-center gap-1 px-3 py-1.5 hover:bg-white/10 rounded-full transition-colors text-sm text-gray-400">
                    <span>Tools</span>
                    <ChevronDown size={14} />
                  </button>
                </div>
                
                <div className="flex items-center gap-2">
                  <button className="flex items-center gap-1 px-3 py-1.5 hover:bg-white/10 rounded-full transition-colors text-sm text-gray-400">
                    <Zap size={14} />
                    <span>Fast</span>
                  </button>
                  <button 
                    onClick={() => handleSendMessage(inputValue)}
                    disabled={!inputValue.trim()}
                    className={`p-2 rounded-full transition-colors ${
                      inputValue.trim() 
                        ? "bg-blue-500 hover:bg-blue-400 text-white" 
                        : "bg-white/10 text-gray-400 cursor-not-allowed"
                    }`}
                  >
                    {isLoading ? (
                      <div className="w-5 h-5 border-2 border-current border-t-transparent rounded-full animate-spin" />
                    ) : (
                      <span className="text-sm font-medium">Send</span>
                    )}
                  </button>
                </div>
              </div>
            </motion.div>

            {/* Desktop: Quick Action Chips - Below input */}
            <div className="hidden md:flex items-center justify-center gap-2 mt-4 flex-wrap">
              {quickActions.map((action, index) => (
                <motion.button
                  key={index}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: index * 0.05 }}
                  onClick={() => handleSendMessage(action.label)}
                  className="flex items-center gap-2 px-4 py-2 bg-[#1e1e1e] hover:bg-[#2a2a2a] border border-[#2a2a2a] rounded-full transition-colors text-sm text-gray-300"
                >
                  <span>{action.icon}</span>
                  <span>{action.label}</span>
                </motion.button>
              ))}
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}
